        x1_im = LD(&in_im[m+1*is]);
        x2_re = LD(&in_re[m+2*is]);
        x2_im = LD(&in_im[m+2*is]);
        x3_re = LD(&in_re[m+3*is]);
        x3_im = LD(&in_im[m+3*is]);
